#!/bin/bash\nset -e\n\nREPO_URL=\"https://github.com/jonatha1723/EVn.git\"\nPROJECT_PATH=\"$HOME/projects/EVn\"\nBRANCH=\"main\"\nHOSTING_TARGET=\"eve-jn\"\n\nif [ ! -d \"$PROJECT_PATH\" ]; then\n    git clone \"$REPO_URL\" \"$PROJECT_PATH\"\nelse\n    cd \"$PROJECT_PATH\"\n    git fetch origin\n    git checkout $BRANCH\n    git pull origin $BRANCH\nfi\n\ncd \"$PROJECT_PATH\"\nnpm install\nnpm run lint\nnpm run build\nfirebase deploy --only hosting:$HOSTING_TARGET\n\necho \"✅ https://eve-jn.web.app/\"\n